      color: '#8b5cf6',
      lineWidth: 3
    });

    Lab.connections.connectObjects(pulleyObj, pulleyObj.rightMassObj, 'rope', {
      stiffness: 100,
      restLength: Math.hypot(pulleyObj.x - pulleyObj.rightMassObj.x, pulleyObj.y - pulleyObj.rightMassObj.y),
      color: '#8b5cf6',
