simulations.update:
function(dt) {
  const atwoodPulley = Lab.state.objects.find(o => o.pluginId === 'atwood_pulley');
  if (!atwoodPulley || !atwoodPulley.leftMassObj || !atwoodPulley.rightMassObj) return;

  const m1 = atwoodPulley.leftMass;
  const m2 = atwoodPulley.rightMass;
  const I = atwoodPulley.momentOfInertia;
  const r = atwoodPulley.w / 100;
  const g = Lab.state.gravity;
  const friction = atwoodPulley.friction;
  const ropeFriction = atwoodPulley.ropeFriction;

  // Aceleração teórica
  const denominator = m1 + m2 + I / (r * r);
  let a = (m2 - m1) * g / denominator;

  // Atrito da corda
  if (Math.abs(atwoodPulley.velocity) > 0.01) {
    const frictionForce = friction * (m1 + m2) * g;
    const frictionAcc = frictionForce / denominator;
    if (a > 0) a = Math.max(0, a - frictionAcc);
    else if (a < 0) a = Math.min(0, a + frictionAcc);
  }

  // Atrito da roldana
  const angularFriction = Math.abs(atwoodPulley.angularVelocity) * ropeFriction;

  // Atualizar velocidades
  atwoodPulley.velocity = (atwoodPulley.velocity || 0) + a * dt;
  atwoodPulley.velocity *= (1 - friction * dt * 0.3);

  atwoodPulley.angularVelocity = (atwoodPulley.angularVelocity || 0) + (a / r) * dt;
  atwoodPulley.angularVelocity *= (1 - angularFriction * dt);

  // Rotação visual
  atwoodPulley.rotationAngle = (atwoodPulley.rotationAngle || 0) + atwoodPulley.angularVelocity * dt * 30;

  // Atualizar posições
  let leftY = (atwoodPulley.leftPosition || 450) - atwoodPulley.velocity * dt;
  let rightY = (atwoodPulley.rightPosition || 450) + atwoodPulley.velocity * dt;

  // Limites
  const minY = 80 + (atwoodPulley.leftMassObj?.w || 28);
  const maxY = 620 - (atwoodPulley.leftMassObj?.w || 28);
  leftY = Math.max(minY, Math.min(maxY, leftY));
  rightY = Math.max(minY, Math.min(maxY, rightY));

  atwoodPulley.leftPosition = leftY;
  atwoodPulley.rightPosition = rightY;

  // Aplicar às massas
  if (atwoodPulley.leftMassObj) {
    atwoodPulley.leftMassObj.y = atwoodPulley.leftPosition;
  }
  if (atwoodPulley.rightMassObj) {
    atwoodPulley.rightMassObj.y = atwoodPulley.rightPosition;
  }
}

